sql:
SELECT AVG(value) AS average_metric_value
FROM delivery_metrics
WHERE metric_type = 'On-Time Delivery';

SELECT request_status
FROM transportation_requests
WHERE driver_id = 1;

SELECT AVG(cost_of_request) AS average_cost
FROM transportation_requests
WHERE client_id = 1;

SELECT metric_type
FROM delivery_metrics
WHERE metric_type = 'On-Time Delivery';

external_knowledge:
; The transport loads have different types, such as bulk or container loads; 
; The transport request status can be either 'Completed', 'Pending', 'Cancelled' etc., but we are interested only in 'Completed' ones; 
; The priorities of transport requests are ranked from high to low.

sql:
SELECT MAX(value) AS max_cost
FROM delivery_metrics
WHERE metric_type = 'Cost';

SELECT load_type_name
FROM load_types
WHERE load_type_id < 2;
